from PIL import Image
import codecs
import pytesseract
import logging
IMAGE_PATH = "image.png"
def task_func(filename=IMAGE_PATH, from_encoding="cp1251", to_encoding="utf8"):

    try:
        with Image.open(filename) as img:
            ocr_text = pytesseract.image_to_string(img)

            try:
                ocr_text = ocr_text.encode(from_encoding).decode(to_encoding)
                return ocr_text
            except (UnicodeDecodeError, LookupError) as e:
                logging.warning(f"Failed to convert OCR text: {e}")

            try:
                comment = img.info.get("Comment")

                if comment is not None:
                    comment = comment.encode(from_encoding).decode(to_encoding)
                    return comment
                else:
                    logging.warning("No comment found in the image")
            except (UnicodeDecodeError, LookupError) as e:
                logging.warning(f"Failed to convert image comment: {e}")

        return ""

    except Exception as e:
        logging.error(f"An error occurred: {e}")
        raise ValueError(f"An error occurred: {e}")

import numpy as np
import matplotlib.pyplot as plt
CITIES = ['New York', 'London', 'Beijing', 'Tokyo', 'Sydney', 'Paris', 'Berlin', 'Moscow', 'Madrid', 'Rome']
def task_func(city_dict, max_range=1000000, seed=0):
    if max_range < 1:
        raise ValueError("max_range must be a positive integer")

    np.random.seed(seed)
    city_population = {
        city: (np.random.randint(1, max_range) if city in CITIES else -1) 
        for _, city in city_dict.items() if isinstance(city, str)
    }

    plt.figure()
    ax = plt.bar(city_population.keys(), city_population.values())
    plt.xlabel('City')
    plt.ylabel('Population')
    plt.title('City Populations')

    return city_population, plt.gca()

