import numpy as np
import csv
def task_func(file_name):
    try:
        with open(file_name, 'r', encoding='utf-8') as file:
            reader = csv.reader(file)
            header = next(reader, None)
            if header is None:
                return {}                                      

            data = list(reader)
            if not data:
                return {col: None for col in header}                                           

            num_cols = len(header)
            most_common_values = {}

            for col_index in range(num_cols):
                column_values = [row[col_index] for row in data]
                value_counts = collections.Counter(column_values)
                if value_counts:
                    most_common = value_counts.most_common()
                    max_count = most_common[0][1]
                    ties = [item[0] for item in most_common if item[1] == max_count]
                    ties.sort()
                    most_common_values[header[col_index]] = ties[0]
                else:
                    most_common_values[header[col_index]] = None
            return most_common_values
    except FileNotFoundError:
        return {}                              
    except Exception as e:
        print(f"An error occurred: {e}")
        return {}

import collections
import csv
def task_func(file_name):
    try:
        with open(file_name, mode='r', newline='', encoding='utf-8') as file:
            reader = csv.DictReader(file)

            if reader.fieldnames is None:
                return {}

            column_data = collections.defaultdict(list)

            for row in reader:
                for column, value in row.items():
                    column_data[column].append(value)

            most_common_values = {}
            for column, values in column_data.items():
                counter = collections.Counter(values)
                most_common = sorted(counter.items(), key=lambda x: (-x[1], x[0]))
                most_common_values[column] = most_common[0][0]

            return most_common_values

    except FileNotFoundError:
        raise FileNotFoundError(f"The file '{file_name}' does not exist.")
    except Exception as e:
        raise RuntimeError(f"An error occurred while processing the file: {e}")

