import pandas as pd
import docx
def task_func(source_directory: str, target_directory: str) -> int:
    source_path = Path(source_directory)
    if not source_path.exists() or not source_path.is_dir():
        raise FileNotFoundError(f"Source directory '{source_directory}' does not exist.")

    target_path = Path(target_directory)
    target_path.mkdir(parents=True, exist_ok=True)

    supported_extensions = {".txt", ".docx", ".xlsx", ".csv"}
    converted_count = 0

    for file in source_path.iterdir():
        if file.is_file() and file.suffix in supported_extensions:
            try:
                if file.suffix == ".txt":
                    with file.open("r", encoding="utf-8") as f:
                        content = f.read()
                elif file.suffix == ".docx":
                    doc = docx.Document(file)
                    content = "\n".join([para.text for para in doc.paragraphs])
                elif file.suffix == ".xlsx":
                    df = pd.read_excel(file, engine="openpyxl")
                    content = df.to_string(index=False)
                elif file.suffix == ".csv":
                    df = pd.read_csv(file)
                    content = df.to_string(index=False)
                else:
                    continue                                                           

                csv_file_path = target_path / f"{file.stem}.csv"
                pd.DataFrame({"Text": [content]}).to_csv(csv_file_path, index=False)

                converted_count += 1
            except Exception as e:
                print(f"Error processing file {file.name}: {e}")

    return converted_count

import inspect
import types
import json
def task_func(f):
    spec = inspect.getfullargspec(f)
    annotations = {k: v.__name__ if isinstance(v, type) else str(v) for k, v in spec.annotations.items()}

    info = {
        'function_name': f.__name__,
        'args': spec.args,
        'defaults': spec.defaults,
        'annotations': annotations,
        'is_lambda': isinstance(f, types.LambdaType)
    }

    return json.dumps(info)

import inspect
import types
import json
def task_func(f):

    is_lambda = isinstance(f, types.LambdaType)

    if is_lambda:
        func_name = "<lambda>"
    else:
        func_name = f.__name__

    signature = inspect.signature(f)

    parameters = []
    for name, param in signature.parameters.items():
        param_info = {
            "name": name,
            "default": param.default if param.default is not inspect.Parameter.empty else None,
            "annotation": str(param.annotation) if param.annotation is not inspect.Parameter.empty else None,
            "kind": str(param.kind)
        }
        parameters.append(param_info)

    annotations = {name: str(annotation) for name, annotation in f.__annotations__.items()} if hasattr(f, '__annotations__') else {}

    func_info = {
        "name": func_name,
        "is_lambda": is_lambda,
        "parameters": parameters,
        "annotations": annotations
    }

    return json.dumps(func_info, indent=4)

import inspect
import types
import json
def task_func(f):
    is_lambda = isinstance(f, types.LambdaType) and f.__name__ == "<lambda>"

    signature = inspect.signature(f)

    args = []
    defaults = {}
    annotations = {}

    for param_name, param in signature.parameters.items():
        args.append(param_name)
        if param.default is not inspect.Parameter.empty:
            defaults[param_name] = param.default
        if param.annotation is not inspect.Parameter.empty:
            annotations[param_name] = str(param.annotation)

    if signature.return_annotation is not inspect.Signature.empty:
        annotations['return'] = str(signature.return_annotation)

    result = {
        "name": f.__name__,
        "args": args,
        "defaults": defaults,
        "annotations": annotations,
        "is_lambda": is_lambda
    }

    return json.dumps(result, indent=4)

import re
import glob
from docx import Document
def task_func(directory_path: str) -> int:
    processed_count = 0
    for filepath in glob.glob(f"{directory_path}/*.docx"):
        try:
            doc = Document(filepath)
            for paragraph in doc.paragraphs:
                if '"' in paragraph.text:
                    paragraph.text = re.sub(r'"', r'\"', paragraph.text)
            for table in doc.tables:
                for row in table.rows:
                    for cell in row.cells:
                        if '"' in cell.text:
                            cell.text = re.sub(r'"', r'\"', cell.text)
            doc.save(filepath)
            processed_count += 1
        except Exception as e:
            print(f"Error processing {filepath}: {e}")
    return processed_count

import re
import glob
from docx import Document
import os
def task_func(directory_path: str) -> int:
    docx_files = glob.glob(os.path.join(directory_path, "*.docx"))
    files_processed = 0

    for file_path in docx_files:
        try:
            doc = Document(file_path)
            modified = False

            for paragraph in doc.paragraphs:
                if '"' in paragraph.text:
                    escaped_text = paragraph.text.replace('"', r'\"')
                    if escaped_text != paragraph.text:
                        paragraph.text = escaped_text
                        modified = True

            if modified:
                doc.save(file_path)
                files_processed += 1

        except Exception as e:
            print(f"Error processing file {file_path}: {e}")

    return files_processed

import os
import re
import datetime
def task_func(pattern, log_dir='/var/log/'):
    try:
        if not os.path.isdir(log_dir):
            return None

        matching_files = []
        for filename in os.listdir(log_dir):
            if re.search(pattern, filename):
                filepath = os.path.join(log_dir, filename)
                if os.path.isfile(filepath):
                    matching_files.append(filepath)

        if not matching_files:
            return None

        latest_file = None
        latest_time = datetime.datetime.min

        for filepath in matching_files:
            file_mod_time = datetime.datetime.fromtimestamp(os.path.getmtime(filepath))
            if file_mod_time > latest_time:
                latest_time = file_mod_time
                latest_file = filepath

        return latest_file
    except Exception:
        return None

import os
import re
def task_func(pattern, log_dir='/var/log/'):
    if not os.path.isdir(log_dir):
        print(f"Directory '{log_dir}' does not exist.")
        return None

    try:
        regex = re.compile(pattern)
    except re.error as e:
        print(f"Invalid regex pattern: {e}")
        return None

    try:
        files = os.listdir(log_dir)
    except OSError as e:
        print(f"Error accessing directory '{log_dir}': {e}")
        return None

    matching_files = [f for f in files if regex.match(f)]

    if not matching_files:
        return None

    latest_file = None
    latest_mtime = None

    for file in matching_files:
        file_path = os.path.join(log_dir, file)
        if os.path.isfile(file_path):                      
            mtime = os.path.getmtime(file_path)                         
            if latest_file is None or mtime > latest_mtime:
                latest_file = file_path
                latest_mtime = mtime

    return latest_file

