import subprocess
import threading
def task_func(file_list):
    def run_subprocess(file, results, index):
        try:
            process = subprocess.run(["python", file], capture_output=True)
            results[index] = process.returncode
        except Exception as e:
            results[index] = -1

    results = [None] * len(file_list)
    threads = []

    for i, file in enumerate(file_list):
        thread = threading.Thread(target=run_subprocess, args=(file, results, i))
        threads.append(thread)
        thread.start()

    for thread in threads:
        thread.join()

    return results

import subprocess
import time
import threading
from concurrent.futures import ThreadPoolExecutor, as_completed
def task_func(file_list):
    results = {}
    with ThreadPoolExecutor() as executor:
        futures = {executor.submit(run_file, file): file for file in file_list}

        for future in as_completed(futures):
            file = futures[future]
            try:
                results[file] = future.result()
            except Exception as e:
                results[file] = e

    exit_codes = [results[file] for file in file_list]

    return exit_codes
def run_file(file):
    process = subprocess.Popen([file], shell=True)
    process.wait()
    return process.returncode

import numpy as np
import random
def task_func(length=10000, seed=0):
    if length < 0:
        raise ValueError("Length must be non-negative.")

    random.seed(seed)

    steps = [random.choice([-1, 1]) for _ in range(length)]

    walk = np.cumsum([0] + steps)              

    return np.array(walk)

