    for category, sales in sales_data.items():
        ax.plot(range(days_diff), sales, label=category)

    ax.set_xlabel("Days since " + start_time.strftime("%Y-%m-%d %H:%M:%S"))
    ax.set_ylabel("Sales")
    ax.legend()

    return sales_data, ax

