import subprocess
import os
import time
import glob
def task_func(r_script_path: str, output_path: str, duration: int) -> (bool, str):
    if not os.path.isfile(r_script_path):
        return False, f"R script not found at path: {r_script_path}"

    initial_files = set(glob.glob(output_path)) if os.path.isdir(output_path) else set([output_path])

    try:
        process = subprocess.Popen(
            ["Rscript", r_script_path],
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE
        )
    except FileNotFoundError:
        return False, "Rscript command not found. Please ensure R is installed and available in PATH."

    start_time = time.time()
    while time.time() - start_time < duration:
        if process.poll() is not None:
            break
        time.sleep(0.1)                                       

    if process.poll() is None:
        process.terminate()                                                    
        return False, "R script execution exceeded the specified duration."

    stdout, stderr = process.communicate()

    if process.returncode != 0:
        return False, f"R script execution failed with error: {stderr.decode('utf-8')}"

    final_files = set(glob.glob(output_path)) if os.path.isdir(output_path) else set([output_path])
    new_files = final_files - initial_files

    if new_files:
        return True, "File generated successfully within the specified duration."
    else:
        return False, "File not generated within the specified duration."

