import re
import json
import os
def task_func(file_path: str, regex_pattern=r'\(.+?\)|\w') -> dict:
    if not os.path.isfile(file_path):
        raise FileNotFoundError(f"The file '{file_path}' does not exist.")

    if not file_path.endswith('.json'):
        raise ValueError(f"The file '{file_path}' is not a JSON file.")

    with open(file_path, 'r', encoding='utf-8') as file:
        try:
            data = json.load(file)
        except json.JSONDecodeError as e:
            raise ValueError(f"Error decoding JSON from file '{file_path}': {e}")

    data_str = json.dumps(data)

    matches = re.findall(regex_pattern, data_str)

    filename = os.path.basename(file_path)
    return {filename: matches}

