import re
import os
def task_func(request):
    if not request.startswith("GET "):
        return "HTTP/1.1 400 Bad Request\r\n\r\nInvalid request method."

    match = re.match(r"GET /([^ ]*) HTTP/1.1", request)
    if not match:
        return "HTTP/1.1 400 Bad Request\r\n\r\nInvalid request format."

    filename = match.group(1)
    if not filename:
        return "HTTP/1.1 400 Bad Request\r\n\r\nNo filename provided."

    if ".." in filename or filename.startswith("/"):
        return "HTTP/1.1 403 Forbidden\r\n\r\nInvalid filename."

    try:
        with open(filename, "rb") as f:
            file_content = f.read()
            content_length = len(file_content)
            response = f"HTTP/1.1 200 OK\r\nContent-Length: {content_length}\r\n\r\n"
            response += file_content.decode('utf-8', errors='ignore')
            return response
    except FileNotFoundError:
        return "HTTP/1.1 404 Not Found\r\n\r\nFile not found."
    except Exception as e:
        return f"HTTP/1.1 500 Internal Server Error\r\n\r\n{str(e)}"

