import requests
import os
import zipfile
def task_func(url, destination_directory, headers=None):
    if not os.path.exists(destination_directory):
        os.makedirs(destination_directory)

    try:
        response = requests.get(url, headers=headers, stream=True)
        response.raise_for_status()                                                  

        zip_file_path = os.path.join(destination_directory, "downloaded.zip")
        with open(zip_file_path, 'wb') as f:
            for chunk in response.iter_content(chunk_size=8192):
                f.write(chunk)

        extracted_files = []
        with zipfile.ZipFile(zip_file_path, 'r') as zip_ref:
            for file_info in zip_ref.infolist():
                extracted_path = os.path.join(destination_directory, file_info.filename)
                if file_info.is_dir():
                    os.makedirs(extracted_path, exist_ok=True)
                else:
                    zip_ref.extract(file_info, destination_directory)
                    extracted_files.append(extracted_path)

        return extracted_files

    except requests.exceptions.RequestException as e:
        print(f"Error during download: {e}")
        return []
    except zipfile.BadZipFile as e:
        print(f"Error: Invalid zip file: {e}")
        return []
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return []
    finally:
        if os.path.exists(zip_file_path):
            os.remove(zip_file_path)

import re
import nltk
from gensim.models import Word2Vec
ALPHANUMERIC = re.compile('[\W_]+')
def task_func(texts, stopwords=None):
    if stopwords is None:
        stopwords = nltk.corpus.stopwords.words('english')

    cleaned_texts = [ALPHANUMERIC.sub(' ', text).lower() for text in texts]
    tokenized_texts = [[word for word in text.split() if word not in stopwords] for text in cleaned_texts]

    if not tokenized_texts:
        return Word2Vec(vector_size=100)

    model = Word2Vec(sentences=tokenized_texts, vector_size=100, window=5, min_count=1, workers=4)

    return model

