import numpy as np
import itertools
import json
def task_func(data_list, json_file_name="mean_values.json"):

    if not data_list:
        return {}

    transposed_data = list(map(list, itertools.zip_longest(*data_list, fillvalue=np.nan)))

    result_dict = {}

    for i, column in enumerate(transposed_data):
        numeric_values = [x for x in column if isinstance(x, (int, float)) and not np.isnan(x)]

        mean_value = np.mean(numeric_values) if numeric_values else np.nan

        result_dict[f'Position {i}'] = mean_value

    if json_file_name:
        with open(json_file_name, 'w') as f:
            json.dump(result_dict, f, indent=4)

    return result_dict
