import base64
import hashlib
import hmac
import binascii
def task_func(s, signature, secret_key):
    try:
        decoded_message = base64.b64decode(s)
    except (binascii.Error, ValueError):
        return False

    computed_hmac = hmac.new(secret_key.encode(), decoded_message, hashlib.sha1).hexdigest()

    return hmac.compare_digest(computed_hmac, signature)

import pandas as pd
import random
from datetime import datetime
def task_func(
    task_list,
    n_tasks,
    employees=["John Doe", "Jane Smith", "James Brown", "Mary Johnson", "Robert Davis"],
    seed=None,
):
    if n_tasks < 0:
        raise ValueError("n_tasks must be a non-negative integer.")

    if seed is not None:
        random.seed(seed)

    sanitized_tasks = [task.replace(" ", "_") for task in task_list]

    if n_tasks > len(sanitized_tasks):
        tasks_to_assign = random.choices(sanitized_tasks, k=n_tasks)
    else:
        tasks_to_assign = random.sample(sanitized_tasks, k=n_tasks)

    assignments = []
    today = datetime.now().date()
    for task in tasks_to_assign:
        employee = random.choice(employees)
        assignments.append({"Task Name": task, "Assigned To": employee, "Due Date": today})

    return pd.DataFrame(assignments)

import os
def task_func(path: str, delimiter: str = os.path.sep) -> list:
    invalid_chars = {'<', '>', ':', '"', '|', '?', '*'}

    normalized_path = path.replace("\\", "/")

    if any(char in normalized_path for char in invalid_chars):
        raise ValueError(f"The path contains invalid characters: {invalid_chars}")

    components = normalized_path.split(delimiter)

    return components

