import importlib
from pkgutil import iter_modules
def task_func(package_name):
    try:
        package = importlib.import_module(package_name)
    except ImportError:
        raise ImportError(f"Package '{package_name}' is not installed. Please install it using: pip install {package_name}")

    package_path = getattr(package, '__path__', None)
    if not package_path:
        raise ImportError(f"Package '{package_name}' does not have a valid path. Please ensure it is installed correctly.")

    module_names = []

    for _, module_name, is_pkg in iter_modules(package_path):
        module_names.append(module_name)

        if is_pkg:
            module_path = os.path.join(package_path[0], module_name)
            if module_path not in sys.path:
                sys.path.append(module_path)

    return module_names

import os
import sys
import importlib
from pkgutil import iter_modules
def task_func(package_name):
    try:
        package = importlib.import_module(package_name)
    except ImportError:
        raise ImportError(f"The package {package_name} is not installed. Please install it using pip: pip install {package_name}")

    package_dir = os.path.dirname(package.__file__)

    added_modules = []

    for module_info in iter_modules([package_dir]):
        module_name = module_info.name

        if module_name not in sys.modules:
            sys.path.insert(0, os.path.join(package_dir, module_name))

            added_modules.append(module_name)

    return added_modules

