import matplotlib.pyplot as plt
import pandas as pd
def task_func(df, tuples, n_plots):

    df_filtered = df.copy()
    for col, val in tuples:
        df_filtered = df_filtered[df_filtered[col] != val]

    if len(df_filtered.columns) < 2:
        return df_filtered, []

    all_pairs = []
    for i in range(len(df_filtered.columns)):
        for j in range(i+1, len(df_filtered.columns)):
            all_pairs.append((df_filtered.columns[i], df_filtered.columns[j]))

    if len(all_pairs) == 0:
        return df_filtered, []

    if len(all_pairs) < n_plots:
        plot_pairs = all_pairs
    else:
        plot_pairs = sample(all_pairs, n_plots)

    for col1, col2 in plot_pairs:
        plt.figure()
        plt.plot(df_filtered[col1], df_filtered[col2])
        plt.xlabel(col1)
        plt.ylabel(col2)
        plt.title(f"Plot of {col1} vs {col2}")
        plt.show()

    return df_filtered, plot_pairs

import json
import requests
import os
from datetime import datetime
def task_func(json_data, unknown_key, save_dir=None):
    try:
        data = json.loads(json_data)
        url = data.get(unknown_key)
        if not url:
            raise ValueError(f"Key '{unknown_key}' not found in JSON data or value is null.")

        response = requests.get(url, stream=True)
        response.raise_for_status()                                                  

        timestamp = datetime.now().strftime('%Y%m%d%H%M%S%f')
        filename = f"{unknown_key}_{timestamp}.txt"

        if save_dir:
            os.makedirs(save_dir, exist_ok=True)
            filepath = os.path.join(save_dir, filename)
        else:
            filepath = filename

        with open(filepath, 'wb') as f:
            for chunk in response.iter_content(chunk_size=8192):
                f.write(chunk)

        return os.path.abspath(filepath)

    except json.JSONDecodeError:
        raise ValueError("Invalid JSON string provided.")
    except requests.exceptions.RequestException as e:
        raise Exception(f"Error during download: {e}")
    except Exception as e:
        raise Exception(f"An unexpected error occurred: {e}")

