import json
import requests
import os
from datetime import datetime
def task_func(json_data, unknown_key, save_dir=None):

    data = json.loads(json_data)

    if unknown_key not in data:
        raise ValueError(f"The key '{unknown_key}' does not exist in the JSON data.")

    url = data[unknown_key]

    if not isinstance(url, str):
        raise ValueError(f"The value of '{unknown_key}' is not a string.")

    if save_dir is None:
        save_dir = os.getcwd()

    if not os.path.exists(save_dir):
        os.makedirs(save_dir)

    timestamp = datetime.now().strftime('%Y%m%d%H%M%S%f')

    filename = f"{unknown_key}_{timestamp}.txt"

    file_path = os.path.join(save_dir, filename)

    try:
        response = requests.get(url)
        response.raise_for_status()                                      
    except requests.exceptions.RequestException as e:
        raise ValueError(f"Failed to download the file from '{url}': {e}")

    with open(file_path, 'wb') as f:
        f.write(response.content)

    return os.path.abspath(file_path)

