import statistics
AGE_RANGE = (22, 60)
def task_func(dict1):

    emp_dollars_employees = [employee for employee in dict1 if employee['department'] == 'EMP$$']

    if not emp_dollars_employees:
        return None

    for employee in emp_dollars_employees:
        if 'age' not in employee:
            employee['age'] = random.randint(AGE_RANGE[0], AGE_RANGE[1])

    ages = [employee['age'] for employee in emp_dollars_employees]

    mean_age = statistics.mean(ages)

    median_age = statistics.median(ages)

    mode_ages = statistics.multimode(ages)

