import re
from datetime import time
def task_func(logs: list):

    error_times = []
    total_time = 0

    for log in logs:
        if "ERROR" in log:
            time_match = re.search(r'(\d{2}):(\d{2}):\d{2}', log)
            if time_match:
                hour, minute = map(int, time_match.groups())
                error_times.append(time(hour, minute))
                total_time += hour * 60 + minute

    if error_times:
        avg_hour = (total_time // len(error_times)) // 60
        avg_minute = (total_time // len(error_times)) % 60
        avg_time = time(avg_hour, avg_minute)
    else:
        avg_time = time(0, 0)

    return error_times, avg_time

import pandas as pd
from datetime import datetime, timedelta
import random
def task_func(
    epoch_milliseconds,
    random_seed=0,
    products=["Product1", "Product2", "Product3", "Product4", "Product5"],
):

    if not isinstance(epoch_milliseconds, int):
        raise ValueError("epoch_milliseconds must be an integer.")
    if not isinstance(random_seed, int):
        raise ValueError("random_seed must be an integer.")
    if not isinstance(products, list):
        raise ValueError("products must be a list.")
    if not all(isinstance(product, str) for product in products):
        raise ValueError("All elements in products must be strings.")
    if len(products) != 5:
        raise ValueError("products list must contain exactly 5 product names.")

    random.seed(random_seed)

    start_date = datetime.fromtimestamp(epoch_milliseconds / 1000)
    end_date = datetime.now()

    sales_data = []
    current_date = start_date.date()
    while current_date <= end_date.date():
        for product in products:
            sales = random.randint(10, 50)
            sales_data.append({
                "Product": product,
                "Date": current_date,
                "Sales": sales
            })
        current_date += timedelta(days=1)

    return pd.DataFrame(sales_data)

import re
from sklearn.feature_extraction.text import TfidfVectorizer
def task_func(texts):

    if all(text.strip() == "" for text in texts):
        return [], []

    cleaned_texts = [re.sub('http[s]?://\S+', '', text) for text in texts]

    vectorizer = TfidfVectorizer()
    tfidf_matrix = vectorizer.fit_transform(cleaned_texts)

    dense_matrix = [tuple(round(val, 8) for val in row) for row in tfidf_matrix.toarray().tolist()]
    return dense_matrix, list(vectorizer.get_feature_names_out())

import re
from sklearn.feature_extraction.text import TfidfVectorizer
def task_func(texts):
    def remove_urls(text):
        url_pattern = r'http[s]?://\S+|www\.\S+'
        return re.sub(url_pattern, '', text)

    cleaned_texts = [remove_urls(text) for text in texts]

    vectorizer = TfidfVectorizer()

    tfidf_matrix = vectorizer.fit_transform(cleaned_texts)

    feature_names = vectorizer.get_feature_names_out()

    dense_tfidf = tfidf_matrix.toarray()
    rounded_tfidf = [tuple(round(score, 8) for score in doc) for doc in dense_tfidf]

    return rounded_tfidf, list(feature_names)

