import re
from pathlib import Path
def task_func(dir_path: str, predicates: list) -> dict:

    if not predicates:
        raise ValueError("No predicates provided.")

    path = Path(dir_path)
    if not path.is_dir():
        raise FileNotFoundError(f"Directory not found or is not a directory: {dir_path}")

    results = {}
    unique_predicates = []
    for pred in predicates:
        if pred not in unique_predicates:
            unique_predicates.append(pred)

    for item in os.listdir(path):
        item_path = path / item
        item_results = []
        for pred in unique_predicates:
            if isinstance(pred, str):
                item_results.append(pred in item)
            elif hasattr(pred, 'match') and callable(pred.match):
                item_results.append(bool(pred.match(item)))
            else:
                raise ValueError(f"Invalid predicate type: {type(pred)}")
        results[item] = item_results
    return results

