import pandas as pd
import numpy as np
def task_func(excel_file_path, file_name, column_name):
    file_path = os.path.join(excel_file_path, file_name)
    if not os.path.exists(file_path):
        raise FileNotFoundError(f"File not found at path: {file_path}")

    try:
        df = pd.read_excel(file_path)
    except Exception as e:
        raise Exception(f"Error reading excel file: {e}")

    if column_name not in df.columns:
        raise ValueError(f"Column '{column_name}' not found in the Excel file.")

    column_data = df[column_name].dropna()

    if column_data.empty:
        return {"mean": np.nan, "median": np.nan, "std": np.nan}

    mean_value = np.mean(column_data)
    median_value = np.median(column_data)
    std_value = np.std(column_data)

    return {"mean": mean_value, "median": median_value, "std": std_value}

