from datetime import datetime
import pytz
import numpy as np
def task_func(time_strings, timezone):
    if len(time_strings) < 2:
        return 0.0

    target_timezone = pytz.timezone(timezone)

    converted_times = []
    for time_str in time_strings:
        dt = datetime.fromisoformat(time_str)
        if dt.tzinfo is None:
            dt = pytz.utc.localize(dt)
        dt_converted = dt.astimezone(target_timezone)
        converted_times.append(dt_converted)

    converted_times.sort()

    time_differences = []
    for i in range(1, len(converted_times)):
        diff = abs((converted_times[i] - converted_times[i - 1]).total_seconds())
        time_differences.append(diff)

    if not time_differences:
        return 0.0

    return float(np.mean(time_differences))

